function weatherCodeMeta(code) {
  return WEATHER_CODE_META[code] || { icon: Cloud, label: { ja: '不明', en: 'Unknown' } };
}
// 雨・雪を伴う天気コードか、または降水確率が高い(60%以上)かを判定する(屋外スポットへの注意表示に使用)
function isRainyForecast(code, precipitationProbability) {
  const rainyCodes = new Set([51, 53, 55, 61, 63, 65, 80, 81, 82, 95, 96, 99]);
  return rainyCodes.has(code) || precipitationProbability >= 60;
}
